        // Replace text in element, preserve child elements (icons, badges)
        function applyText(el, text) {
            if (!el || text === undefined || text === null) return;
            var kids = Array.from(el.childNodes);
            var hasElement = kids.some(function(n) { return n.nodeType === 1; });
            if (hasElement) {
                var replaced = false;
                for (var i = 0; i < kids.length; i++) {
                    if (kids[i].nodeType === 3 && kids[i].nodeValue.trim()) {
                        kids[i].nodeValue = (i > 0 ? ' ' : '') + text;
                        replaced = true;
                        break;
                    }
                }
                if (!replaced) el.appendChild(document.createTextNode(' ' + text));
            } else {
                el.textContent = text;
            }
        }

        // Ambil value key dari dict aktif; jika kosong fallback ke Bahasa Indonesia.
        // Untuk lang 'id' & 'en' (parity penuh) hasilnya identik dgn sebelumnya.
        function _tkey(dict, key) {
            var v = dict[key];
            return (v === undefined || v === null || v === '') ? T.id[key] : v;
        }

        function applyLanguage(lang) {
            if (!T[lang]) lang = 'id';
            var dict = T[lang];

            // 1. Desktop nav labels (semua .main-tab-btn, termasuk clone di #favorites-container)
            document.querySelectorAll('.main-tab-btn[data-tab]').forEach(function(btn) {
                var tabId = btn.dataset.tab;
                var text = _tkey(dict, 'nav.' + tabId);
                if (!text) return;
                var span = btn.querySelector('.btn-text');
                if (span) applyText(span, text);
            });

            // 2. Mobile nav labels
            document.querySelectorAll('.mobile-tab-btn[data-tab]').forEach(function(btn) {
                var tabId = btn.dataset.tab;
                var text = _tkey(dict, 'nm.' + tabId) || _tkey(dict, 'nav.' + tabId);
                if (!text) return;
                var spans = btn.querySelectorAll('span:not(.new-badge):not(.fav-star-mobile)');
                if (spans.length > 0) spans[0].textContent = text;
            });

            // 3. Category headers — data-i18n-cat
            document.querySelectorAll('[data-i18n-cat]').forEach(function(el) {
                var key = el.dataset.i18nCat;
                var text = _tkey(dict, 'cat.' + key);
                if (text) applyText(el, text);
            });

            // 4. Panel h1 — pattern content-{tabId} header h1
            document.querySelectorAll('[id^="content-"] header h1').forEach(function(h1) {
                var panel = h1.closest('[id^="content-"]');
                if (!panel) return;
                var tabId = panel.id.replace(/^content-/, '');
                var text = _tkey(dict, 'headers.' + tabId);
                if (text) applyText(h1, text);
            });

            // 5. Generic data-i18n elements
            document.querySelectorAll('[data-i18n]').forEach(function(el) {
                var key = el.dataset.i18n;
                var text = _tkey(dict, key);
                if (text) applyText(el, text);
            });

            // 6. Placeholder translation
            document.querySelectorAll('[data-i18n-placeholder]').forEach(function(el) {
                var key = el.dataset.i18nPlaceholder;
                var text = _tkey(dict, key);
                if (text) el.placeholder = text;
            });

            // 7. HTML content translation (pakai innerHTML untuk rich content dengan <br>, <strong>)
            document.querySelectorAll('[data-i18n-html]').forEach(function(el) {
                var key = el.dataset.i18nHtml;
                var text = _tkey(dict, key);
                if (text) el.innerHTML = text;
            });

            // 8. Runtime phrase replacement — scan all text nodes, replace known ID phrases with EN
            applyRuntimeTranslations(lang);

            // Update <html lang>
            document.documentElement.lang = lang;
        }

