        const AD_URL = "https://www.profitablecpmratenetwork.com/cruvfekt?key=e9e907eb7243c5ba2443b17b570520f9";
        const LYNK_BEBAS_IKLAN_URL = "https://lynk.id/arullagi/9plw09dw01l9";
        // [v33+] Lynk.id paid feature: "fitur favorit tab affgo" (lifetime). Saat user
        // klik bintang dan flag belum aktif → buka link ini di tab baru.
        const LYNK_FAVORIT_FEATURE_URL = "https://lynk.id/arullagi/rm306vzjzjx0";
        const AD_LOCK_DURATION_MS = 10000; // overlay countdown 10 detik
        const AD_COOLDOWN_MS = 5000;       // jeda min antar trigger iklan
        // POC: hanya tab Membuat Model dulu — kalau OK, baru rollout ke semua tab.

        window.isAdFree = false;
        // [v33+] Favorit Tab feature gate. Default OFF — di-set true oleh login/cek
        // response kalau user sudah bayar (kolom M = "AKTIF" di sheet Affiliate GO Users).
        window.favoritFeatureActive = false;
        let __lastAdTime = 0;
        let __adInProgress = false;

        function __adsConfigured() {
            return AD_URL.indexOf("YOUR-") === -1;
        }
        function __lynkConfigured() {
            return LYNK_BEBAS_IKLAN_URL.indexOf("YOUR-") === -1;
        }

        // Buka iklan di tab baru + tampilkan overlay countdown 10 detik (locked).
        // Resolve setelah countdown selesai → caller bisa lanjutkan aksi asli.
        function __showAdAndWait() {
            return new Promise((resolve) => {
                // 1. Buka iklan di tab baru — HARUS sinkron di user-gesture handler
                try { window.open(AD_URL, "_blank", "noopener"); } catch (e) {}

                // 2. Bangun overlay
                const lang = (localStorage.getItem("app_language") || "en").toLowerCase();
                const T = lang === "id" ? {
                    title: "Mohon Tunggu", sec: "Detik",
                    sub: "Iklan sudah terbuka di tab baru. Aksi akan dilanjutkan otomatis...",
                    pitch: "Capek nunggu iklan terus?",
                    pitchSub: "Berlangganan Bebas Iklan",
                    cta: "🚀 Berlangganan Sekarang",
                    perMo: "/bln"
                } : {
                    title: "Please Wait", sec: "Sec",
                    sub: "An ad has opened in a new tab. Action will resume automatically...",
                    pitch: "Tired of ads?",
                    pitchSub: "Subscribe to Ad-Free",
                    cta: "🚀 Subscribe Now",
                    perMo: "/mo"
                };

                const totalSec = Math.max(1, Math.round(AD_LOCK_DURATION_MS / 1000));
                const overlay = document.createElement("div");
                overlay.id = "ad-lock-overlay";
                overlay.innerHTML =
                    '<div class="ad-lock-card">' +
                        '<div class="ad-lock-title">⏱ ' + T.title + ' <span class="ad-lock-counter" id="ad-lock-counter">' + totalSec + '</span> ' + T.sec + '</div>' +
                        '<div class="ad-lock-subtitle">' + T.sub + '</div>' +
                        '<div class="ad-lock-progress"><div class="ad-lock-progress-fill" id="ad-lock-progress-fill"></div></div>' +
                        '<div class="ad-lock-divider"></div>' +
                        '<div class="ad-lock-pitch">' +
                            '<div class="ad-lock-pitch-emoji">💎</div>' +
                            '<div class="ad-lock-pitch-text">' + T.pitch + '</div>' +
                            '<div class="ad-lock-pitch-sub">' + T.pitchSub + '</div>' +
                            '<div class="ad-lock-price">Rp 14.000<span class="ad-lock-price-unit">' + T.perMo + '</span></div>' +
                            '<button type="button" id="ad-lock-cta">' + T.cta + '</button>' +
                        '</div>' +
                    '</div>';
                document.body.appendChild(overlay);

                const ctaBtn = overlay.querySelector("#ad-lock-cta");
                if (ctaBtn) {
                    if (!__lynkConfigured()) {
                        // Selama Lynk.id URL masih placeholder, sembunyikan tombol CTA upsell
                        ctaBtn.style.display = "none";
                    } else {
                        ctaBtn.addEventListener("click", () => {
                            try { window.open(LYNK_BEBAS_IKLAN_URL, "_blank", "noopener"); } catch (e) {}
                        });
                    }
                }

                const counterEl = overlay.querySelector("#ad-lock-counter");
                const fillEl = overlay.querySelector("#ad-lock-progress-fill");

                // Mulai progress bar dengan transisi linier sepanjang durasi
                requestAnimationFrame(() => {
                    requestAnimationFrame(() => {
                        if (fillEl) {
                            fillEl.style.transition = "width " + AD_LOCK_DURATION_MS + "ms linear";
                            fillEl.style.width = "100%";
                        }
                    });
                });

                let remaining = totalSec;
                const interval = setInterval(() => {
                    remaining--;
                    if (counterEl) counterEl.textContent = remaining > 0 ? remaining : 0;
                    if (remaining <= 0) {
                        clearInterval(interval);
                        overlay.style.transition = "opacity .25s ease-out";
                        overlay.style.opacity = "0";
                        setTimeout(() => {
                            overlay.remove();
                            resolve();
                        }, 250);
                    }
                }, 1000);
            });
        }

        // Update badge status di pojok kanan atas berdasarkan window.isAdFree
        function updateAdFreeBadge() {
            let badge = document.getElementById("ad-free-status-badge");
            const loggedIn = !!localStorage.getItem("affiliatego_email");

            if (!loggedIn) {
                if (badge) badge.style.display = "none";
                return;
            }
            if (!badge) {
                badge = document.createElement("div");
                badge.id = "ad-free-status-badge";
                document.body.appendChild(badge);
            }
            badge.style.display = "block";

            const lang = (localStorage.getItem("app_language") || "en").toLowerCase();
            if (window.isAdFree) {
                const txt = lang === "id" ? "✓ Bebas Iklan Aktif" : "✓ Ad-Free Active";
                badge.innerHTML = '<div class="ad-free-active-badge">' + txt + '</div>';
            } else if (__lynkConfigured()) {
                const txt = lang === "id" ? "🚫 Bebas Iklan Rp 14.000/bln" : "🚫 Go Ad-Free";
                badge.innerHTML = '<button type="button" class="ad-free-cta-btn">' + txt + '</button>';
                const btn = badge.querySelector("button");
                if (btn) {
                    btn.addEventListener("click", () => {
                        try { window.open(LYNK_BEBAS_IKLAN_URL, "_blank", "noopener"); } catch (e) {}
                    });
                }
            } else {
                // Lynk.id URL masih placeholder — sembunyikan badge CTA agar user non-bayar tidak klik tombol broken
                badge.style.display = "none";
            }
        }
        window.updateAdFreeBadge = updateAdFreeBadge;

        // Gerbang iklan untuk satu tombol (capture phase).
        // Tombol asli akan dicegah, lalu di-fire ulang setelah countdown selesai.
        function __attachAdGate(target) {
            if (!target || target.__adGateAttached) return;
            target.__adGateAttached = true;
            target.addEventListener("click", function (e) {
                if (window.isAdFree) return;
                if (!__adsConfigured()) return; // failsafe: placeholder URL = sistem iklan off
                if (__adInProgress) {
                    e.preventDefault();
                    e.stopImmediatePropagation();
                    return;
                }
                if (target.dataset.adBypass === "1") {
                    delete target.dataset.adBypass;
                    return; // fire ulang setelah ad — biarkan handler asli jalan
                }

                const now = Date.now();
                if (now - __lastAdTime < AD_COOLDOWN_MS) return; // cooldown 5 detik

                e.preventDefault();
                e.stopImmediatePropagation();

                __lastAdTime = now;
                __adInProgress = true;

                __showAdAndWait().then(() => {
                    target.dataset.adBypass = "1";
                    target.click();
                }).catch(() => {}).finally(() => {
                    __adInProgress = false;
                });
            }, true); // capture phase: jalan SEBELUM handler bubble milik IIFE
        }

        // Generic: pasang gerbang iklan untuk semua tombol Generate/Download di satu tab.
        // Konvensi ID yang harus dipenuhi tab tersebut:
        //   - Generate button:    "{prefix}-generate-btn"
        //   - Download All:       "{prefix}-download-all-btn"
        //   - Results grid:       "{prefix}-results-grid" — per-card download pakai
        //                         [data-action="download"] di dalam grid (delegated)
        // Opsional override:
        //   - `customGridId`: untuk tab dengan grid ID non-standard
        //                     (contoh: "broll-b-roll-grid", "result-image-container")
        //   - `customGenerateId`: untuk tab dengan generate button ID non-standard
        //                         (contoh: "new-born-generate-button" pakai -button bukan -btn)
        function __attachAdGateToTab(prefix, customGridId, customGenerateId) {
            const generateBtn = document.getElementById(customGenerateId || (prefix + "-generate-btn"));
            const downloadAllBtn = document.getElementById(prefix + "-download-all-btn");
            const resultsGrid = document.getElementById(customGridId || (prefix + "-results-grid"));

            if (generateBtn) __attachAdGate(generateBtn);
            if (downloadAllBtn) __attachAdGate(downloadAllBtn);

            if (resultsGrid && !resultsGrid.__adGateGridAttached) {
                resultsGrid.__adGateGridAttached = true;
                resultsGrid.addEventListener("click", function (e) {
                    if (window.isAdFree) return;
                    if (!__adsConfigured()) return;

                    // Match generic "download" action serta namespaced action seperti
                    // "broll-download", "wedding-download", dll yang dipakai oleh banyak
                    // tab — tanpa perubahan markup. Pattern $="-download" cover semuanya.
                    const btn = e.target.closest('[data-action="download"], [data-action$="-download"]');
                    if (!btn) return;

                    if (__adInProgress) {
                        e.preventDefault();
                        e.stopImmediatePropagation();
                        return;
                    }
                    if (btn.dataset.adBypass === "1") {
                        delete btn.dataset.adBypass;
                        return;
                    }
                    const now = Date.now();
                    if (now - __lastAdTime < AD_COOLDOWN_MS) return;

                    e.preventDefault();
                    e.stopImmediatePropagation();

                    __lastAdTime = now;
                    __adInProgress = true;

                    __showAdAndWait().then(() => {
                        btn.dataset.adBypass = "1";
                        btn.click();
                    }).catch(() => {}).finally(() => {
                        __adInProgress = false;
                    });
                }, true); // capture phase
            }
        }

