        // Re-check setiap 3 detik di background → overlay otomatis hilang saat AdBlock off.
        (function() {
            function detectAdblock() {
                return new Promise(function(resolve) {
                    var bait = document.createElement('div');
                    bait.innerHTML = '&nbsp;';
                    bait.className = 'ads ad-banner ad-unit adsbox adsbygoogle pub_300x250 pub_300x250m pub_728x90 text-ad textAd text_ad text_ads text-ads text-ad-links';
                    bait.style.cssText = 'position:absolute;left:-9999px;top:-9999px;height:5px;width:5px;background:transparent;';
                    document.body.appendChild(bait);
                    setTimeout(function() {
                        var cs = window.getComputedStyle(bait);
                        var isBlocked = (
                            bait.offsetHeight === 0 ||
                            bait.clientHeight === 0 ||
                            bait.offsetParent === null ||
                            cs.display === 'none' ||
                            cs.visibility === 'hidden'
                        );
                        bait.remove();
                        resolve(isBlocked);
                    }, 120);
                });
            }

            function ensureOverlayElement() {
                var ov = document.getElementById('adblock-overlay');
                if (ov) return ov;
                ov = document.createElement('div');
                ov.id = 'adblock-overlay';
                ov.innerHTML = (
                    '<div class="adblock-card">' +
                        '<div class="adblock-icon"><i class="fas fa-shield-halved"></i></div>' +
                        '<div class="adblock-title" data-i18n="adblock.title">AdBlock Terdeteksi</div>' +
                        '<div class="adblock-desc" data-i18n="adblock.desc">Aplikasi ini gratis berkat iklan. Matikan AdBlock dulu untuk lanjut menggunakan aplikasi, atau dapatkan akses tanpa iklan permanen dengan Bebas Iklan.</div>' +
                        '<div class="adblock-steps">' +
                            '<strong data-i18n="adblock.howto-label">Cara matikan:</strong> ' +
                            '<span data-i18n="adblock.howto-text">Klik ikon AdBlock di toolbar browser → pilih "Disable on this site" / "Pause on this site" → refresh halaman.</span>' +
                        '</div>' +
                        '<div class="adblock-actions">' +
                            '<button type="button" class="adblock-btn-recheck" id="adblock-recheck-btn">' +
                                '<i class="fas fa-rotate-right"></i> <span data-i18n="adblock.recheck">Saya Sudah Matikan — Cek Ulang</span>' +
                            '</button>' +
                            '<a href="' + LYNK_BEBAS_IKLAN_URL + '" target="_blank" rel="noopener" class="adblock-btn-buy">' +
                                '<i class="fas fa-shield-halved"></i> <span data-i18n="adblock.buy">Beli Bebas Iklan Rp 14.000/bln</span>' +
                            '</a>' +
                        '</div>' +
                    '</div>'
                );
                document.body.appendChild(ov);
                var recheckBtn = ov.querySelector('#adblock-recheck-btn');
                if (recheckBtn) {
                    recheckBtn.addEventListener('click', function() { runAdblockCheck(); });
                }
                if (typeof window._i18nApplyNow === 'function') window._i18nApplyNow();
                return ov;
            }

            function showOverlay() {
                var ov = ensureOverlayElement();
                ov.classList.add('active');
                document.body.style.overflow = 'hidden';
            }
            function hideOverlay() {
                var ov = document.getElementById('adblock-overlay');
                if (ov) ov.classList.remove('active');
                document.body.style.overflow = '';
            }

            function runAdblockCheck() {
                // Skip kalau user sudah ad-free (premium) — tidak perlu blokir
                if (window.isAdFree === true) { hideOverlay(); return; }
                detectAdblock().then(function(blocked) {
                    if (blocked) showOverlay(); else hideOverlay();
                });
            }

            function init() {
                runAdblockCheck();
                // Auto re-check 3s — overlay hilang otomatis saat user matikan AdBlock
                setInterval(runAdblockCheck, 3000);
            }
            if (document.readyState === 'loading') {
                document.addEventListener('DOMContentLoaded', init);
            } else {
                init();
            }
            window.runAdblockCheck = runAdblockCheck;
        })();
        // ==================== END ADBLOCK DETECTION ====================

        // ==================== UTILITY FUNCTIONS ====================

        // Generate Token Unik untuk Device
        function generateToken() {
            return Math.random().toString(36).substr(2, 9) + Date.now().toString(36) + Math.random().toString(36).substr(2, 9);
        }

        // ==================== LOGIN FUNCTIONS ====================

        // Fungsi 1: Proses Login
        function prosesLogin() {
            const email = document.getElementById('emailInput').value.trim();
            const loading = document.getElementById('loadingMsg');
            const error = document.getElementById('errorMsg');
            const loginBtn = document.querySelector('.login-btn');

            // Validasi email
            if (!email) {
                error.innerText = "⚠️ Email wajib diisi!";
                return;
            }

            // Validasi format email
            const emailRegex = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
            if (!emailRegex.test(email)) {
                error.innerText = "⚠️ Format email tidak valid!";
                return;
            }

            // Show loading
            loading.style.display = "block";
            error.innerText = "";
            loginBtn.disabled = true;
            loginBtn.innerHTML = '<i class="fas fa-spinner fa-spin"></i> MEMVERIFIKASI...';

            // Generate Token Baru
            const newToken = generateToken();

            // Panggil Google Apps Script (Action: login)
            fetch(SCRIPT_URL + "?action=login&email=" + encodeURIComponent(email) + "&token=" + encodeURIComponent(newToken) + "&app_secret=" + encodeURIComponent(APP_SECRET) + "&product=" + encodeURIComponent(PRODUCT_ID))
                .then(res => res.json())
                .then(data => {
                    loading.style.display = "none";
                    loginBtn.disabled = false;
                    loginBtn.innerHTML = '<i class="fas fa-sign-in-alt"></i> MASUK APLIKASI';

                    if (data.status === "SUKSES") {
                        // Simpan kredensial di localStorage
                        localStorage.setItem("affiliatego_email", email);
                        localStorage.setItem("affiliatego_token", newToken);
                        localStorage.setItem("affiliatego_name", data.nama || "User");

                        // Status Bebas Iklan dari server
                        window.isAdFree = !!data.ad_free;
                        if (typeof updateAdFreeBadge === "function") updateAdFreeBadge();

                        // [v33+] Favorit Tab paid feature — flag dari server adalah source of truth.
                        // Kalau aktif, override localStorage favorit dengan data cloud + render ulang.
                        // Kalau tidak aktif, biarkan localStorage (user lama mungkin sudah punya
                        // favorit lokal — tetap kelihatan tapi click bintang akan munculkan paywall
                        // sebelum bisa toggle/sync).
                        window.favoritFeatureActive = !!data.favorit_feature_active;
                        if (window.favoritFeatureActive && Array.isArray(data.favorites) && typeof window._affApplyFavoritesFromServer === "function") {
                            window._affApplyFavoritesFromServer(data.favorites);
                        }

                        // Buka aplikasi
                        bukaAplikasi(data.nama || "User");
                    } else {
                        error.innerText = "❌ " + (data.message || "Email tidak terdaftar. Pastikan sudah membeli Affiliate GO.");
                    }
                })
                .catch(err => {
                    loading.style.display = "none";
                    loginBtn.disabled = false;
                    loginBtn.innerHTML = '<i class="fas fa-sign-in-alt"></i> MASUK APLIKASI';
                    error.innerText = "❌ Gagal koneksi ke server. Periksa koneksi internet Anda.";
                    console.error("Login error:", err);
                });
        }

        // ==================== POPUP BEBAS IKLAN LOGIN ====================
        // Tampil sekali per device setelah login (manual / auto-login).
        // Skip kalau user sudah ad-free atau sudah pernah lihat popup di device ini.
        // Flag di-set saat SHOW (bukan close) supaya semua jalur close (X, ESC,
        // backdrop, "Lain Kali") otomatis tercakup tanpa hook tambahan.
        function showAdFreePromoIfEligible(nama) {
            if (window.isAdFree === true) return;
            try { if (localStorage.getItem('adfree_promo_seen') === '1') return; } catch (e) { return; }
            if (typeof window.showUniversalModal !== 'function') return;
            // Failsafe: kalau Adsterra tidak terkonfigurasi (AD_URL placeholder),
            // ad gating mati → popup ini juga skip (tidak relevan).
            if (typeof __adsConfigured === 'function' && !__adsConfigured()) return;

            try { localStorage.setItem('adfree_promo_seen', '1'); } catch (e) {}

            const isEN = (localStorage.getItem('app_language') || 'id') === 'en';
            const safeName = String(nama || 'User').replace(/[<>&"']/g, function(c) {
                return { '<': '&lt;', '>': '&gt;', '&': '&amp;', '"': '&quot;', "'": '&#39;' }[c];
            });
            const greeting = isEN
                ? 'Hi ' + safeName + ', welcome! 👋'
                : 'Halo ' + safeName + ', selamat datang! 👋';
            const title = isEN ? 'AffGo Ad-Free' : 'Bebas Iklan AffGo';

            const html =
                '<div class="text-center">' +
                    '<p class="text-base font-medium text-gray-800 mb-3">' + greeting + '</p>' +
                    '<div class="text-5xl mb-3" style="filter: drop-shadow(0 4px 12px rgba(234, 88, 12, 0.4));">🛡️</div>' +
                    '<p class="text-base font-semibold text-gray-700 mb-4" data-i18n="adfree-popup.headline">Coba pengalaman tanpa iklan</p>' +
                    '<ul class="text-left space-y-2 mb-5 max-w-sm mx-auto">' +
                        '<li class="flex items-start gap-2 text-sm text-gray-700"><i class="fas fa-check-circle text-green-600 mt-1"></i><span data-i18n="bebas-iklan.feature-1">Tanpa iklan saat Generate / Download</span></li>' +
                        '<li class="flex items-start gap-2 text-sm text-gray-700"><i class="fas fa-check-circle text-green-600 mt-1"></i><span data-i18n="bebas-iklan.feature-2">Akses penuh tanpa interupsi 1 bulan</span></li>' +
                        '<li class="flex items-start gap-2 text-sm text-gray-700"><i class="fas fa-check-circle text-green-600 mt-1"></i><span data-i18n="bebas-iklan.feature-3">Auto-aktif setelah pembayaran (login ulang)</span></li>' +
                    '</ul>' +
                    '<a href="' + LYNK_BEBAS_IKLAN_URL + '" target="_blank" rel="noopener noreferrer" ' +
                        'class="inline-flex items-center justify-center gap-2 w-full bg-gradient-to-r from-orange-600 to-orange-700 text-white font-bold py-3 px-6 rounded-xl shadow-lg hover:shadow-xl hover:scale-[1.02] active:scale-[0.98] transition-all min-h-[44px]">' +
                        '<i class="fas fa-shield-halved"></i><span data-i18n="bebas-iklan.cta">Beli Sekarang — Rp 14.000 / bulan</span>' +
                    '</a>' +
                    '<button type="button" id="adfree-popup-skip-btn" class="mt-3 w-full text-sm font-semibold text-gray-500 hover:text-gray-700 py-2 min-h-[44px]" data-i18n="adfree-popup.skip">Lain Kali</button>' +
                    '<p class="text-xs text-gray-500 mt-3" data-i18n="bebas-iklan.note">Setelah bayar, login ulang dengan email yang sama</p>' +
                '</div>';

            window.showUniversalModal(title, html);

            // "Lain Kali" → trigger universal modal close button (programmatic click).
            // Defer so the button exists in DOM after showUniversalModal injects content.
            setTimeout(function() {
                const skipBtn = document.getElementById('adfree-popup-skip-btn');
                const closeBtn = document.getElementById('close-modal-btn');
                if (skipBtn && closeBtn) {
                    skipBtn.addEventListener('click', function() { closeBtn.click(); });
                }
            }, 50);
        }
        window.showAdFreePromoIfEligible = showAdFreePromoIfEligible;
        // ==================== END POPUP BEBAS IKLAN LOGIN ====================

        // Fungsi 2: Buka Aplikasi (Unlock Main App)
        function bukaAplikasi(nama) {
            // Hide login overlay
            document.getElementById('login-overlay').style.display = 'none';

            // Show main app
            const mainApp = document.getElementById('main-app');
            mainApp.classList.add('unlocked');

            // Show user info badge
            const userBadge = document.getElementById('userInfoBadge');
            userBadge.classList.add('active');
            document.getElementById('userNameDisplay').innerText = nama;

            // Start session monitoring (check every 10 seconds)
            setInterval(jagaSesi, 10000);

            // Tampilkan popup Bebas Iklan setelah delay (sekali per device, lihat
            // showAdFreePromoIfEligible untuk guard logic). Delay 1.5s supaya user
            // lihat dashboard dulu sebelum popup muncul.
            setTimeout(function() { showAdFreePromoIfEligible(nama); }, 1500);
        }

        // Fungsi 3: Jaga Sesi (Security Check)
        function jagaSesi() {
            const email = localStorage.getItem("affiliatego_email");
            const token = localStorage.getItem("affiliatego_token");

            if (!email || !token) return;

            // Panggil Google Apps Script (Action: cek)
            fetch(SCRIPT_URL + "?action=cek&email=" + encodeURIComponent(email) + "&token=" + encodeURIComponent(token) + "&app_secret=" + encodeURIComponent(APP_SECRET) + "&product=" + encodeURIComponent(PRODUCT_ID))
                .then(res => res.json())
                .then(data => {
                    if (data.status === "INVALID") {
                        // Token tidak cocok - akun login di tempat lain
                        alert("⚠️ SESI BERAKHIR!\n\nAkun Anda sedang digunakan di perangkat lain.\nAnda akan dikembalikan ke halaman login.");
                        logout();
                    } else if (data.status === "VALID") {
                        // Refresh status Bebas Iklan tiap 10 detik (mengikuti polling sesi)
                        const wasAdFree = window.isAdFree;
                        window.isAdFree = !!data.ad_free;
                        if (wasAdFree !== window.isAdFree && typeof updateAdFreeBadge === "function") {
                            updateAdFreeBadge();
                        }
                        // [v33+] Refresh status fitur Favorit Tab — supaya saat user baru bayar
                        // di tab lain, dalam <10 detik flag terupdate dan paywall popup berhenti.
                        window.favoritFeatureActive = !!data.favorit_feature_active;
                    }
                })
                .catch(err => {
                    // Skip jika error koneksi (agar tidak ganggu user)
                    console.log("Session check skipped due to connection issue");
                });
        }

        // Fungsi 4: Auto Login (saat page load/refresh)
        window.addEventListener('load', function() {
            const email = localStorage.getItem("affiliatego_email");
            const token = localStorage.getItem("affiliatego_token");
            const nama = localStorage.getItem("affiliatego_name");

            if (email && token && nama) {
                // Tampilkan loading
                document.getElementById('loadingMsg').style.display = "block";

                // Verifikasi token ke server
                fetch(SCRIPT_URL + "?action=cek&email=" + encodeURIComponent(email) + "&token=" + encodeURIComponent(token) + "&app_secret=" + encodeURIComponent(APP_SECRET) + "&product=" + encodeURIComponent(PRODUCT_ID))
                    .then(res => res.json())
                    .then(data => {
                        document.getElementById('loadingMsg').style.display = "none";

                        if (data.status === "VALID") {
                            // Status Bebas Iklan dari server saat auto-login
                            window.isAdFree = !!data.ad_free;
                            if (typeof updateAdFreeBadge === "function") updateAdFreeBadge();

                            // Token masih valid, langsung buka aplikasi
                            bukaAplikasi(nama);
                        } else {
                            // Token tidak valid, hapus localStorage
                            localStorage.clear();
                            document.getElementById('errorMsg').innerText = "⚠️ Sesi telah berakhir. Silakan login kembali.";
                        }
                    })
                    .catch(err => {
                        document.getElementById('loadingMsg').style.display = "none";
                        // Jika error koneksi, tetap coba buka (offline mode)
                        console.log("Auto-login verification failed, opening anyway");
                        bukaAplikasi(nama);
                    });
            }
        });

        // Fungsi 5: Logout
        function logout() {
            // Clear localStorage
            localStorage.removeItem("affiliatego_email");
            localStorage.removeItem("affiliatego_token");
            localStorage.removeItem("affiliatego_name");

            // Reload page (akan kembali ke login screen)
            location.reload();
        }

        // Fungsi 6: Enter key support untuk login
        document.addEventListener('DOMContentLoaded', function() {
            const emailInput = document.getElementById('emailInput');
            if (emailInput) {
                emailInput.addEventListener('keypress', function(e) {
                    if (e.key === 'Enter') {
                        prosesLogin();
                    }
                });
            }
        });
    
